//! Observation detection: "active deception when observed."
//!
//! Per-connection telemetry is fed through the three mesh witnesses
//! (`crate::mesh`). When any fires, the connection is recognized as an observer
//! and the policy verdict hardens (Allow/Redirect -> Trap). This is the rogue's
//! defining reflex: it does not announce a defense (that is x-ranger's tank
//! posture); it simply notices it is being watched and slips the watcher
//! somewhere innocuous.

use crate::mesh::{
    clock_side_channel_bypass, overlay_hole_bypass, zenonic_approach_bypass, Clock, Gap, Overlay,
};

/// Rolling per-connection telemetry. A real front updates this from request
/// metadata; here it is a plain value object so detection stays pure and testable.
#[derive(Debug, Clone)]
pub struct ObservationLedger {
    /// Distinct paths this connection has touched (path-enumeration pressure).
    pub distinct_paths: u64,
    /// Size of the routable region (the addressable surface).
    pub region_size: u64,
    /// Size of the camouflaged/defended overlay the front presents.
    pub defended_overlay: u64,
    /// Defender heartbeat rate (the front's published cadence).
    pub heartbeat_rate: f64,
    /// Observed probe rate of this connection.
    pub probe_rate: f64,
    /// Sampling horizon for the clock comparison.
    pub horizon: f64,
    /// The connection's request-gap contraction (slowloris shape).
    pub gap: Gap,
    /// How many contraction steps have been observed without completion.
    pub gap_iterations: u64,
}

impl Default for ObservationLedger {
    fn default() -> Self {
        ObservationLedger {
            distinct_paths: 0,
            region_size: 1024,
            defended_overlay: 1024,
            heartbeat_rate: 1.0,
            probe_rate: 0.0,
            horizon: 0.0,
            gap: Gap { num: 0, denom: 1 },
            gap_iterations: 0,
        }
    }
}

/// The outcome of running the witnesses over a ledger.
#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub struct Observation {
    pub adversarial: bool,
    pub signatures: Vec<&'static str>,
}

/// Threshold for how many contraction steps without landing reads as slowloris.
const SLOWLORIS_PATIENCE: u64 = 8;

/// How many reclaimable holes (distinct enumerated paths that fit disjointly in
/// the region) read as a path-enumeration sweep rather than ordinary browsing.
/// The mesh witness fires for any disjoint fit; the *detector* waits for a sweep.
const ENUMERATION_THRESHOLD: u64 = 12;

/// Run all three witnesses; a connection is adversarial if any fires.
pub fn observe(ledger: &ObservationLedger) -> Observation {
    let mut signatures: Vec<&'static str> = Vec::new();

    // 1. Path enumeration: the connection's footprint reclaims holes in the
    //    camouflaged overlay (additive-disjoint fit inside the region).
    let hole = overlay_hole_bypass(
        Overlay {
            size: ledger.defended_overlay,
        },
        Overlay {
            size: ledger.distinct_paths,
        },
        ledger.region_size,
    );
    if hole.reclaimed_hits >= ENUMERATION_THRESHOLD {
        signatures.push("overlayHoleBypass");
    }

    // 2. Clock-rate side channel: probing faster than the heartbeat.
    let clock = clock_side_channel_bypass(
        Clock {
            rate: ledger.heartbeat_rate,
        },
        Clock {
            rate: ledger.probe_rate,
        },
        ledger.horizon,
    );
    if clock.strictly_positive {
        signatures.push("clockRateSideChannel");
    }

    // 3. Zenonic approach / slowloris: a long contraction run that never lands.
    let zeno = zenonic_approach_bypass(ledger.gap, ledger.gap_iterations);
    if ledger.gap.num > 0 && ledger.gap_iterations >= SLOWLORIS_PATIENCE && !zeno.has_landed {
        signatures.push("zenonicApproachBypass");
    }

    Observation {
        adversarial: !signatures.is_empty(),
        signatures,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn quiet_legitimate_connection_is_not_adversarial() {
        // Touches a couple of paths, probes slower than heartbeat, no slowloris.
        let ledger = ObservationLedger {
            distinct_paths: 0,
            region_size: 1024,
            defended_overlay: 1024,
            heartbeat_rate: 10.0,
            probe_rate: 1.0,
            horizon: 5.0,
            gap: Gap { num: 0, denom: 1 },
            gap_iterations: 0,
        };
        let o = observe(&ledger);
        assert!(!o.adversarial, "a quiet caller must pass unnoticed");
        assert!(o.signatures.is_empty());
    }

    #[test]
    fn path_enumeration_is_detected_only_past_threshold() {
        let sweep = ObservationLedger {
            distinct_paths: 16,
            region_size: 1024,
            defended_overlay: 8,
            ..ObservationLedger::default()
        };
        let o = observe(&sweep);
        assert!(o.adversarial);
        assert!(o.signatures.contains(&"overlayHoleBypass"));

        // A handful of distinct paths is ordinary browsing, not a sweep.
        let browsing = ObservationLedger {
            distinct_paths: 3,
            region_size: 1024,
            defended_overlay: 8,
            ..ObservationLedger::default()
        };
        assert!(!observe(&browsing).signatures.contains(&"overlayHoleBypass"));
    }

    #[test]
    fn fast_probing_is_detected() {
        let ledger = ObservationLedger {
            heartbeat_rate: 1.0,
            probe_rate: 50.0,
            horizon: 10.0,
            ..ObservationLedger::default()
        };
        let o = observe(&ledger);
        assert!(o.signatures.contains(&"clockRateSideChannel"));
    }

    #[test]
    fn slowloris_is_detected_only_after_patience() {
        let ledger = ObservationLedger {
            gap: Gap { num: 1, denom: 1 },
            gap_iterations: SLOWLORIS_PATIENCE + 4,
            ..ObservationLedger::default()
        };
        assert!(observe(&ledger).signatures.contains(&"zenonicApproachBypass"));

        let early = ObservationLedger {
            gap: Gap { num: 1, denom: 1 },
            gap_iterations: 1,
            ..ObservationLedger::default()
        };
        assert!(!observe(&early).signatures.contains(&"zenonicApproachBypass"));
    }
}
